mapper.select:
SELECT p.id, p.title, p.slug, p.description, p.tags, p.img_urls AS imgUrls, u.avatar AS authorAvatar, u.nickname AS authorNickname, u.tags_json AS authorTagJson, p.publish_time AS publishTime, p.is_top AS isTop FROM posts p JOIN users u ON p.creator_id = u.id WHERE p.status = 'published' AND p.visible = 'public' AND JSON_CONTAINS(p.tags, JSON_QUOTE(#{tagName}))
AND p.creator_id = #{creatorId}
ORDER BY p.publish_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT p.status, p.update_time AS updateTime
FROM posts p
WHERE p.id = #{id}

SELECT p.status, p.update_time AS updateTime
FROM posts p
WHERE p.slug = #{slug}

