#{id}
AND p.status = 'published' AND p.visible IN ('public', 'followers')

SELECT id
FROM posts
WHERE creator_id = #{creatorId}
  AND status = 'published'
  AND visible IN ('public', 'followers')
  AND publish_time >= #{since}
ORDER BY publish_time DESC
LIMIT #{limit}

